class Solution:
    def validSequence(self, word1: str, word2: str) -> List[int]:
        n, m = len(word1), len(word2)
        next_pos = [n] * (n + 1)
        for i in range(n - 1, -1, -1):
            next_pos[i] = next_pos[i + 1]
            if word1[i] == word2[0]:
                next_pos[i] = i
        res = []
        i = 0
        diff = 0
        for j in range(m):
            idx = next_pos[i]
            if idx == n:
                return []
            res.append(idx)
            i = idx + 1
            if word1[idx] != word2[j]:
                diff += 1
                if diff > 1:
                    return []
        return res

